sql:
SELECT DISTINCT location_id, sensor_id
FROM sensors
ORDER BY location_id ASC;

SELECT DISTINCT sensor_id 
FROM sensor_data 
WHERE year = 2022;

SELECT COUNT(DISTINCT sensor_id) AS total_sensor_count
FROM sensor_data
WHERE year = 2022;

SELECT quality_status, COUNT(*) AS count
FROM data_quality
GROUP BY quality_status;
